13	export type CollaborationConflictQueueV1 = {
14	  format: 'collaborationConflictQueue_v1';
15	  reason: string;
16	  firstBlockingCommandIndex: number | null;
17	  firstBlockingCommandStep1Based: number | null;
18	  blockingCommandType: string | null;
19	  blockingRuleIds: string[];
20	  affectedElementIds: string[];
21	  rows: CollaborationConflictRowV1[];
22	  inspectionReadout: string;
23	  inspectionReadoutSecondary: string | null;
24	  retryAdvice: CollaborationRetryAdvice;
25	  mergePreflightReadout: string | null;
