38	  if (!v || typeof v !== 'object' || Array.isArray(v)) return null;
39	  const vv = v as Record<string, unknown>;
40	  const ruleIdRaw =
41	    typeof vv.ruleId === 'string' ? vv.ruleId : typeof vv.rule_id === 'string' ? vv.rule_id : '';
42	  const ruleId = ruleIdRaw.trim();
43	  if (!ruleId) return null;
44	
45	  const sev = vv.severity as string | undefined;
46	  const severity: CollaborationConflictRowV1['severity'] =
47	    sev === 'error' || sev === 'warning' || sev === 'info' ? sev : 'warning';
48	
49	  const elementIdsRaw = vv.elementIds ?? vv.element_ids;
50	  const elementIds =
51	    Array.isArray(elementIdsRaw) && elementIdsRaw.every((x) => typeof x === 'string')
52	      ? [...elementIdsRaw]
53	      : [];
54	
55	  const message = typeof vv.message === 'string' ? vv.message : '';
56	  const blocking = typeof vv.blocking === 'boolean' ? vv.blocking : false;
57	
58	  return { ruleId, elementIds, severity, blocking, message };
59	}
