66	  const r = reason.trim();
67	  if (MANUAL_EDIT_REASONS.has(r)) return 'requires_manual_edit';
68	  if (r === 'constraint_error' || hasBlockingRows) return 'blocked';
69	  if (!r && !hasBlockingRows) return 'safe';
70	  return 'blocked';
71	}
