73	function readReplayDiagnostics(detail: Record<string, unknown>) {
74	  const replayRaw = detail.replayDiagnostics;
75	  const replay =
76	    replayRaw && typeof replayRaw === 'object' && !Array.isArray(replayRaw)
77	      ? (replayRaw as Record<string, unknown>)
78	      : null;
79	
80	  let firstBlockingCommandIndex: number | null = null;
81	  if (replay && 'firstBlockingCommandIndex' in replay) {
82	    const n = Number(replay.firstBlockingCommandIndex);
