84	  }
85	
86	  let blockingViolationRuleIds: string[] = [];
87	  const rulesRaw = replay?.blockingViolationRuleIds;
88	  if (Array.isArray(rulesRaw)) {
89	    blockingViolationRuleIds = rulesRaw
90	      .filter((x): x is string => typeof x === 'string' && x.trim().length > 0)
91	      .map((s) => s.trim());
92	  }
93	
94	  let commandTypesInOrder: string[] = [];
95	  const typesRaw = replay?.commandTypesInOrder;
96	  if (Array.isArray(typesRaw) && typesRaw.every((x) => typeof x === 'string')) {
97	    commandTypesInOrder = typesRaw as string[];
98	  }
99	
100	  return {
101	    replay,
