108	function buildInspectionReadout(params: {
109	  step1: number | null;
110	  commandType: string | null;
111	  blockingRuleIds: string[];
112	  affectedElementIds: string[];
113	  retryAdvice: CollaborationRetryAdvice;
114	}): { primary: string; secondary: string | null } {
115	  const { step1, commandType, blockingRuleIds, affectedElementIds, retryAdvice } = params;
116	  const maxIds = 5;
117	  const idHint =
118	    affectedElementIds.length > 0
119	      ? affectedElementIds.slice(0, maxIds).join(', ') +
120	        (affectedElementIds.length > maxIds
121	          ? ` (+${affectedElementIds.length - maxIds} more)`
122	          : '')
123	      : null;
124	
125	  const rulesHint =
126	    blockingRuleIds.length > 0
127	      ? blockingRuleIds.slice(0, 6).join(', ') + (blockingRuleIds.length > 6 ? ', …' : '')
128	      : null;
129	
130	  const stepChunk =
131	    step1 !== null
132	      ? `Blocking step ${step1}${commandType ? ` (${commandType})` : ''}`
133	      : commandType
134	        ? `Blocking command type ${commandType}`
135	        : 'Replay conflict';
136	
137	  const mid =
138	    [rulesHint ? `rules: ${rulesHint}` : null, idHint ? `elements: ${idHint}` : null]
139	      .filter(Boolean)
140	      .join(' · ') || null;
141	
142	  const primary = [stepChunk, mid, 'Cross-check in Advisor / validation.'].filter(Boolean).join(' ');
143	
144	  let secondary: string | null = null;
145	  if (retryAdvice === 'requires_manual_edit') {
146	    secondary = 'Retry: fix command references, declared ids, or sketch payload before re-applying.';
147	  } else if (retryAdvice === 'blocked') {
148	    secondary = 'Retry: not safe with the same commands — edit the model or trim the bundle, then re-try.';
149	  } else {
150	    secondary = 'Retry: may be safe once local model state matches the server revision.';
151	  }
152	
153	  return { primary, secondary };
154	}
155	
156	/** Stable workspace/agent-review lines from POST bundle mergePreflight_v1 / 409 detail. */
157	export function formatMergePreflightV1Readout(mp: Record<string, unknown>): {
158	  primary: string;
159	  secondary: string | null;
160	} {
161	  if (mp.format !== 'commandBundleMergePreflight_v1') {
162	    return { primary: '', secondary: null };
163	  }
164	  const reason = typeof mp.reasonCode === 'string' ? mp.reasonCode.trim() : '';
165	  const stepRaw = mp.firstConflictingStepIndex;
166	  const step1Based =
167	    typeof stepRaw === 'number' && Number.isFinite(stepRaw) && stepRaw >= 0
168	      ? Math.floor(stepRaw) + 1
169	      : null;
170	  const cls = typeof mp.safeRetryClassification === 'string' ? mp.safeRetryClassification.trim() : '';
171	  const manual = typeof mp.suggestedManualAction === 'string' ? mp.suggestedManualAction.trim() : '';
172	  const agentAct = typeof mp.suggestedAgentAction === 'string' ? mp.suggestedAgentAction.trim() : '';
173	
174	  const declared = Array.isArray(mp.conflictingDeclaredIds)
175	    ? mp.conflictingDeclaredIds.filter((x): x is string => typeof x === 'string')
176	    : [];
177	  const existing = Array.isArray(mp.conflictingExistingElementIds)
178	    ? mp.conflictingExistingElementIds.filter((x): x is string => typeof x === 'string')
179	    : [];
180	  const hints = Array.isArray(mp.missingReferenceHints) ? mp.missingReferenceHints : [];
181	
182	  const maxIds = 5;
183	  const declHint =
184	    declared.length > 0
185	      ? `declared: ${declared.slice(0, maxIds).join(', ')}` +
186	        (declared.length > maxIds ? ` (+${declared.length - maxIds})` : '')
187	      : null;
188	  const existHint =
189	    existing.length > 0
190	      ? `existing: ${existing.slice(0, maxIds).join(', ')}` +
191	        (existing.length > maxIds ? ` (+${existing.length - maxIds})` : '')
192	      : null;
193	
194	  let missingHint: string | null = null;
195	  const h0 = hints[0];
196	  if (h0 !== undefined && h0 !== null && typeof h0 === 'object' && !Array.isArray(h0)) {
197	    const hr = h0 as Record<string, unknown>;
198	    const rk = typeof hr.referenceKey === 'string' ? hr.referenceKey : '';
199	    const rid = typeof hr.referenceId === 'string' ? hr.referenceId : '';
200	    const siRaw = hr.stepIndex;
201	    const si1 =
202	      typeof siRaw === 'number' && Number.isFinite(siRaw) && siRaw >= 0 ? Math.floor(siRaw) + 1 : null;
203	    missingHint =
204	      `missing ${rk}${rid !== '' ? `=${rid}` : ''}` + (si1 !== null ? ` @ step ${si1}` : '');
205	  }
206	
207	  const digestRaw = mp.evidenceDigestSha256;
208	  const digestHint =
209	    typeof digestRaw === 'string' && digestRaw.length >= 16 ? `digest ${digestRaw.slice(0, 16)}…` : null;
210	
211	  const primary = [
212	    reason ? `Merge preflight: ${reason}` : 'Merge preflight',
213	    step1Based !== null ? `first conflicting step ${step1Based}` : null,
214	    cls ? `classification ${cls}` : null,
215	    [declHint, existHint, missingHint].filter(Boolean).join(' · ') || null,
216	    digestHint,
217	  ]
218	    .filter(Boolean)
219	    .join(' · ');
220	
221	  const secondary =
222	    manual !== '' || agentAct !== ''
223	      ? `${manual}${manual !== '' && agentAct !== '' ? ' — ' : ''}${agentAct !== '' ? `Agent: ${agentAct}` : ''}`
224	      : null;
225	
226	  return { primary, secondary };
227	}
228	
229	/** Static inspection steps for Agent Review (no live 409 required). */
230	export function collaborationConflictQueueInspectionLinesFromHints(): string[] {
231	  return [
232	    'Map replayDiagnostics.firstBlockingCommandIndex (0-based) to commandTypesInOrder for the blocking command type.',
233	    'Join blockingViolationRuleIds with violations[].ruleId; use Advisor with those rule ids and elementIds.',
234	    'When replayPerformanceBudget_v1.largeBundleWarn is true, consider splitting or shrinking command bundles before replay.',
235	    'Read mergePreflight_v1 for deterministic safeRetryClassification, first conflicting step, ids/refs, and evidenceDigestSha256.',
236	  ];
237	}
238	
239	export function buildCollaborationConflictQueueV1(detail: unknown): CollaborationConflictQueueV1 | null {
240	  if (!detail || typeof detail !== 'object' || Array.isArray(detail)) return null;
241	  const d = detail as Record<string, unknown>;
242	
243	  const reason = typeof d.reason === 'string' ? d.reason.trim() : '';
244	  const violationsRaw = d.violations;
245	  const violationsList = Array.isArray(violationsRaw) ? violationsRaw : [];
246	
247	  const { firstBlockingCommandIndex, blockingViolationRuleIds, commandTypesInOrder, replay } =
248	    readReplayDiagnostics(d);
249	
250	  const mergeProbe = d.mergePreflight_v1;
251	  const hasMergePreflight =
252	    mergeProbe !== null && typeof mergeProbe === 'object' && !Array.isArray(mergeProbe);
253	
254	  const hasReplay = replay !== null;
255	  const hasViolations = violationsList.length > 0;
256	
257	  if (!reason && !hasViolations && !hasReplay && !hasMergePreflight) return null;
258	
259	  const ruleFilter =
260	    blockingViolationRuleIds.length > 0 ? new Set(blockingViolationRuleIds) : null;
261	
262	  const rowCandidates: CollaborationConflictRowV1[] = [];
263	  for (const v of violationsList) {
264	    const row = parseViolationEntry(v);
265	    if (!row) continue;
266	    const isBlockingOrError = row.blocking || row.severity === 'error';
267	    if (!isBlockingOrError) continue;
268	    if (ruleFilter !== null && !ruleFilter.has(row.ruleId)) continue;
269	    rowCandidates.push(row);
270	  }
271	
272	  rowCandidates.sort((a, b) => rowSortKey(a).localeCompare(rowSortKey(b)));
273	
274	  const blockingRuleIdsFromRows = [...new Set(rowCandidates.map((r) => r.ruleId))].sort();
275	
276	  const blockingRuleIds =
277	    blockingViolationRuleIds.length > 0 ? [...blockingViolationRuleIds].sort() : blockingRuleIdsFromRows;
278	
279	  const affectedSet = new Set<string>();
280	  for (const r of rowCandidates) {
281	    for (const id of r.elementIds) affectedSet.add(id);
282	  }
283	  const affectedElementIds = [...affectedSet].sort();
284	
285	  let blockingCommandType: string | null = null;
286	  if (
287	    firstBlockingCommandIndex !== null &&
288	    firstBlockingCommandIndex >= 0 &&
289	    firstBlockingCommandIndex < commandTypesInOrder.length
290	  ) {
291	    blockingCommandType = commandTypesInOrder[firstBlockingCommandIndex] ?? null;
292	  }
293	
294	  const hasBlockingRows = rowCandidates.length > 0;
295	  const retryAdvice = computeRetryAdvice(reason, hasBlockingRows);
296	
297	  const step1Based =
298	    firstBlockingCommandIndex !== null ? firstBlockingCommandIndex + 1 : null;
299	
300	  const { primary, secondary } = buildInspectionReadout({
301	    step1: step1Based,
302	    commandType: blockingCommandType,
303	    blockingRuleIds,
304	    affectedElementIds,
305	    retryAdvice,
306	  });
307	
308	  let mergePreflightReadout: string | null = null;
309	  let mergePreflightReadoutSecondary: string | null = null;
310	  if (hasMergePreflight) {
311	    const mf = formatMergePreflightV1Readout(mergeProbe as Record<string, unknown>);
312	    mergePreflightReadout = mf.primary.trim() !== '' ? mf.primary : null;
313	    mergePreflightReadoutSecondary = mf.secondary;
314	  }
315	
316	  return {
317	    format: 'collaborationConflictQueue_v1',
318	    reason,
319	    firstBlockingCommandIndex,
320	    firstBlockingCommandStep1Based: step1Based,
321	    blockingCommandType,
322	    blockingRuleIds,
323	    affectedElementIds,
324	    rows: rowCandidates,
325	    inspectionReadout: primary,
326	    inspectionReadoutSecondary: secondary,
327	    retryAdvice,
328	    mergePreflightReadout,
329	    mergePreflightReadoutSecondary,
330	  };
331	}
