10	import { Icons, ICON_SIZE } from '@bim-ai/ui';
11	
12	/**
13	 * StatusBar — spec §17.
14	 *
15	 * 28 px tall surface bar, bottom-of-shell. Shows clusters from left to
16	 * right: active level, current tool, snap mode group, grid toggle, model
17	 * coordinates, undo depth, ws connection, save state.
18	 *
19	 * - Coordinates use `aria-live="polite"` so screen-readers can announce
20	 *   changes without interrupting.
21	 * - The save-state pill uses `aria-live="polite"` too.
22	 * - Errors / red-alert states (offline, save failed) use
23	 *   `aria-live="assertive"`.
24	 * - Every cluster has a tooltip via `title` and a hotkey hint where the
25	 *   spec specifies one (`F3` for snap cycle, `F7` for grid).
26	 */
27	
28	export type StatusSaveState = 'saved' | 'saving' | 'unsynced' | 'error';
29	export type StatusWsState = 'connected' | 'reconnecting' | 'offline';
30	
31	export interface StatusBarProps {
32	  level: { id: string; label: string };
33	  levels?: { id: string; label: string }[];
34	  onLevelChange?: (id: string) => void;
35	  toolLabel?: string | null;
36	  /** Snap mode group; toggling individual snaps lives here. */
37	  snapModes?: { id: string; label: string; on: boolean }[];
38	  onSnapToggle?: (id: string) => void;
39	  gridOn?: boolean;
40	  onGridToggle?: () => void;
41	  /** Live cursor model coords, in mm; null when off-canvas. */
42	  cursorMm?: { xMm: number; yMm: number } | null;
43	  /** Undo depth; clicking the cluster invokes undo / redo. */
44	  undoDepth?: number;
45	  onUndo?: () => void;
46	  onRedo?: () => void;
47	  wsState?: StatusWsState;
48	  saveState?: StatusSaveState;
49	}
50	
51	export function StatusBar({
52	  level,
53	  levels = [],
54	  onLevelChange,
55	  toolLabel,
56	  snapModes = [],
57	  onSnapToggle,
58	  gridOn = true,
59	  onGridToggle,
60	  cursorMm,
61	  undoDepth,
62	  onUndo,
63	  onRedo,
64	  wsState = 'connected',
65	  saveState = 'saved',
66	}: StatusBarProps): JSX.Element {
67	  return (
68	    <div
69	      data-testid="status-bar"
70	      role="contentinfo"
71	      style={statusStyle}
72	      className="flex w-full items-center gap-3 border-t border-border bg-surface px-4 text-xs"
73	    >
74	      <LevelCluster level={level} levels={levels} onLevelChange={onLevelChange} />
75	      <Divider />
76	      <ToolCluster toolLabel={toolLabel ?? null} />
77	      <Divider />
78	      <SnapCluster snapModes={snapModes} onSnapToggle={onSnapToggle} />
79	      <Divider />
80	      <GridCluster gridOn={gridOn} onGridToggle={onGridToggle} />
81	      <Divider />
82	      <CoordCluster cursorMm={cursorMm ?? null} />
83	      <div className="ml-auto flex items-center gap-3">
84	        <UndoCluster depth={undoDepth ?? 0} onUndo={onUndo} onRedo={onRedo} />
85	        <Divider />
86	        <WsCluster state={wsState} />
87	        <Divider />
88	        <SaveCluster state={saveState} />
89	      </div>
90	    </div>
91	  );
92	}
93	
94	const statusStyle: CSSProperties = {
95	  height: 'var(--shell-statusbar-height)',
96	  minHeight: 'var(--shell-statusbar-height)',
97	};
98	
99	function Divider(): JSX.Element {
100	  return <span aria-hidden="true" className="inline-block h-3 w-px bg-border" />;
101	}
102	
103	function LevelCluster({
104	  level,
105	  levels,
106	  onLevelChange,
107	}: {
108	  level: { id: string; label: string };
109	  levels: { id: string; label: string }[];
110	  onLevelChange?: (id: string) => void;
111	}): JSX.Element {
112	  const [open, setOpen] = useState(false);
113	  const popoverId = useId();
114	  const close = useCallback(() => setOpen(false), []);
115	  const handleKey = useCallback(
116	    (event: KeyboardEvent<HTMLDivElement>) => {
117	      if (event.key === 'PageDown' || event.key === 'PageUp') {
118	        if (!levels.length) return;
119	        const idx = levels.findIndex((l) => l.id === level.id);
120	        if (idx < 0) return;
121	        const delta = event.key === 'PageDown' ? 1 : -1;
122	        const next = levels[(idx + delta + levels.length) % levels.length];
123	        event.preventDefault();
124	        onLevelChange?.(next.id);
125	      } else if (event.key === 'Escape') {
126	        close();
127	      }
128	    },
129	    [close, level.id, levels, onLevelChange],
130	  );
131	
132	  return (
133	    <div onKeyDown={handleKey} className="relative flex items-center gap-1">
134	      <button
135	        type="button"
136	        aria-expanded={open}
137	        aria-controls={popoverId}
138	        aria-haspopup="menu"
139	        onClick={() => setOpen((v) => !v)}
140	        title="Active level — PageUp/PageDown to cycle"
141	        className="rounded-sm px-1.5 py-0.5 hover:bg-surface-strong"
142	      >
143	        Level: <span className="font-medium text-foreground">{level.label}</span>
144	        <Icons.disclosureOpen size={ICON_SIZE.chrome} aria-hidden="true" className="ml-1 inline" />
145	      </button>
146	      {open ? (
147	        <div
148	          id={popoverId}
149	          role="menu"
150	          aria-label="Levels"
151	          className="absolute bottom-full left-0 z-50 mb-1 w-48 rounded-md border border-border bg-surface text-sm shadow-elev-2"
152	        >
153	          {levels.map((l) => (
154	            <button
155	              key={l.id}
156	              type="button"
157	              role="menuitem"
158	              onClick={() => {
159	                onLevelChange?.(l.id);
160	                close();
161	              }}
162	              className={[
163	                'flex w-full items-center justify-between px-3 py-1.5 text-left',
164	                l.id === level.id ? 'bg-accent-soft text-foreground' : 'hover:bg-surface-strong',
165	              ].join(' ')}
166	            >
167	              {l.label}
168	              {l.id === level.id ? <span className="text-xs text-muted">active</span> : null}
169	            </button>
170	          ))}
171	        </div>
172	      ) : null}
173	    </div>
174	  );
175	}
176	
177	function ToolCluster({ toolLabel }: { toolLabel: string | null }): JSX.Element {
178	  return (
179	    <div aria-live="polite" className="flex items-center gap-1" title="Active tool">
180	      Tool: <span className="font-medium text-foreground">{toolLabel ?? '—'}</span>
181	    </div>
182	  );
183	}
184	
185	function SnapCluster({
186	  snapModes,
187	  onSnapToggle,
188	}: {
189	  snapModes: { id: string; label: string; on: boolean }[];
190	  onSnapToggle?: (id: string) => void;
191	}): JSX.Element {
192	  return (
193	    <div className="flex items-center gap-1" title="Snap modes — F3 to cycle">
194	      <Icons.snap size={ICON_SIZE.chrome} aria-hidden="true" className="text-muted" />
195	      <span>Snap:</span>
196	      <div role="group" aria-label="Snap modes" className="flex items-center gap-1">
197	        {snapModes.length === 0 ? (
198	          <span className="text-muted">off</span>
199	        ) : (
200	          snapModes.map((s) => (
201	            <button
202	              key={s.id}
203	              type="button"
204	              role="switch"
205	              aria-checked={s.on}
206	              onClick={() => onSnapToggle?.(s.id)}
207	              data-active={s.on ? 'true' : 'false'}
208	              className={[
209	                'rounded-sm px-1.5 py-0.5',
210	                s.on ? 'bg-accent-soft text-foreground' : 'text-muted hover:bg-surface-strong',
211	              ].join(' ')}
212	            >
213	              {s.label}
214	            </button>
215	          ))
216	        )}
217	      </div>
218	    </div>
219	  );
220	}
221	
222	function GridCluster({
223	  gridOn,
224	  onGridToggle,
225	}: {
226	  gridOn: boolean;
227	  onGridToggle?: () => void;
228	}): JSX.Element {
229	  return (
230	    <button
231	      type="button"
232	      role="switch"
233	      aria-checked={gridOn}
234	      onClick={onGridToggle}
235	      title="Grid (F7)"
236	      className="flex items-center gap-1 rounded-sm px-1.5 py-0.5 hover:bg-surface-strong"
237	    >
238	      <Icons.grid size={ICON_SIZE.chrome} aria-hidden="true" />
239	      Grid: <span className="font-medium">{gridOn ? 'ON' : 'OFF'}</span>
240	    </button>
241	  );
242	}
243	
244	function CoordCluster({
245	  cursorMm,
246	}: {
247	  cursorMm: { xMm: number; yMm: number } | null;
248	}): JSX.Element {
249	  return (
